    function fmtInt(v){ return (v===undefined||v===null) ? '\u2014' : String(Math.round(Number(v))); }
    function fmt1(v){
      if(v===undefined||v===null) return '\u2014';
      var n=Number(v);
      return isNaN(n) ? '\u2014' : n.toFixed(1);
    }
    function numOrU(v){
      var n=Number(v);
      return isFinite(n) ? n : undefined;
    }
    function fToC(f){ return (Number(f)-32)*(5/9); }
    function fmtTempFromF(fVal, isC){
      var n=numOrU(fVal);
      if(n===undefined) return '\u2014';
      return String(Math.round(isC ? fToC(n) : n));
    }
    function setTempLabels(isC){
      var unit=isC?'C':'F';
      var ck=document.getElementById('ckptTmpLbl'); if(ck) ck.innerHTML='CKPT SET &deg;'+unit;
      var cb=document.getElementById('cabTmpLbl'); if(cb) cb.innerHTML='CAB TMP &deg;'+unit;
      var mn=document.getElementById('manTmpLbl'); if(mn) mn.innerHTML='MAN SET &deg;'+unit;
      var sp=document.getElementById('setpointLbl'); if(sp) sp.innerHTML='SETPOINT &deg;'+unit;
      var cv=document.getElementById('cabVentLbl'); if(cv) cv.innerHTML='CAB VENT &deg;'+unit;
    }
    function bleedStateLabel(v){
      var n=Number(v);
      if(n===1) return 'OFF';
      if(n===0) return 'R';
      if(n===2) return 'L';
      if(n===3) return 'BOTH';
      if(n===4) return 'R AUTO';
      if(n===5) return 'BOTH AUTO';
      return '\u2014';
    }

    function dimBtn(id, dimmed){
      var el=document.getElementById(id);
      if(!el) return;
      el.style.opacity = dimmed ? '0.35' : '1';
      el.style.pointerEvents = dimmed ? 'none' : '';
    }

