    function fmtNum(v, dec){
      if(v===undefined||v===null) return '\u2014';
      var n=Number(v);
      return isNaN(n) ? '\u2014' : n.toFixed(dec);
    }
    function numOrU(v){
      var n=Number(v);
      return isFinite(n) ? n : undefined;
    }
    function clamp(n,min,max){ return Math.max(min, Math.min(max, n)); }
    /* Gen load: interior GenMaxAmps=300, var_CorrectedGeneratorAmps from GENALT amps times busV over 28V. */
    var GEN_LOAD_FULL_SCALE_AMPS = 300;
    function toLoadPct(amps){
      if(amps===undefined||amps===null) return undefined;
      var n=Number(amps);
      if(isNaN(n)) return undefined;
      return clamp((Math.abs(n)/GEN_LOAD_FULL_SCALE_AMPS)*100, 0, 999);
    }
    function normalizePct(v){
      if(v===undefined||v===null) return undefined;
      var n=Number(v);
      if(isNaN(n)) return undefined;
      // Some vars return 0..1, others 0..100.
      if(n<=1.2) n=n*100;
      return clamp(n,0,999);
    }
    function readCorrectedGenAmps(idx){
      var name=(idx===1)?'var_CorrectedGeneratorAmps_L':'var_CorrectedGeneratorAmps_R';
      return numOrU(getLVar(name,'Number'));
    }
    /* Integer % like cockpit digital readout (nearest whole). */
    function fmtLoadPctInt(pct){
      if(pct===undefined||pct===null||isNaN(Number(pct))) return '\u2014';
      return String(Math.round(clamp(Number(pct),0,999)));
    }
    var _lastGenLoadPct={1:0,2:0};
    function isGenSideOnline(idx){
      var lName=(idx===1)?'var_GeneratorOnline_L':'var_GeneratorOnline_R';
      var o=numOrU(getLVar(lName,'Number'));
      if(o===1) return true;
      if(o===0) return false;
      /* Match interior macro: alternator on + prop RPM > 200 */
      var altOn=getAVar('GENERAL ENG MASTER ALTERNATOR:'+idx+', Bool')==1;
      var rpm=numOrU(getAVar('PROP RPM:'+idx+', rpm'));
      return altOn && rpm!==undefined && rpm>200;
    }
    function getGenLoadPct(side){
      var idx=(side===2)?2:1;
      var on=isGenSideOnline(idx);
      if(!on){
        _lastGenLoadPct[idx]=0;
        return 0;
      }

      /* 1) Aircraft-defined load (interior GenMaxAmps 300 + var_CorrectedGeneratorAmps_*) */
      var corrected=readCorrectedGenAmps(idx);
      var pct=toLoadPct(corrected);
      if(pct!==undefined){
        _lastGenLoadPct[idx]=pct;
        return pct;
      }

      /* 2) Recompute same formula as interior if L: is missing this frame */
      var amps=numOrU(getAVar('ELECTRICAL GENALT BUS AMPS:'+idx+', amps'));
      if(amps!==undefined){
        var volts=numOrU(getAVar('ELECTRICAL GENALT BUS VOLTAGE:'+idx+', volts'));
        if(volts!==undefined) amps = amps * (volts/28);
        pct=toLoadPct(amps);
        if(pct!==undefined){
          _lastGenLoadPct[idx]=pct;
          return pct;
        }
      }

      /* 3) Native sim % — can diverge ~1 from pedestal multimeter */
      pct=normalizePct(getAVar('ELECTRICAL GENALT LOAD:'+idx+', percent'));
      if(pct!==undefined){
        _lastGenLoadPct[idx]=pct;
        return pct;
      }

      return _lastGenLoadPct[idx];
    }

function pollPedestal(){ try {
/* Electrical gauges */
      var battAmps = getAVar('ELECTRICAL BATTERY LOAD:1, amps');
      var lLoadPct = getGenLoadPct(1);
      var rLoadPct = getGenLoadPct(2);

      var voltMode = getLVar('var_MultimeterMode','Number');
      if(voltMode===undefined||voltMode===null) voltMode=0;
      voltMode=Number(voltMode);
      var modeLabel = VOLT_MODES[voltMode] || 'L GEN';

      var vmEl=document.getElementById('gVoltMode');
      if(vmEl) vmEl.textContent = modeLabel;

      var battAmpsMode = getLVar('var_BatteryAmpsMode','Bool')==1;
      setValDisplay('gBattAmp', battAmpsMode ? fmtNum(battAmps,0) : fmtLoadPctInt(lLoadPct));
      setValDisplay('gRLoad', fmtLoadPctInt(rLoadPct));

      var voltsLVar = VOLT_SOURCE_LVARS[voltMode] || 'var_Multimeter_LeftBusVolts';
      var selVolts = getLVar(voltsLVar,'Number');
      if(selVolts===undefined||selVolts===null){
        // Fallback if multimeter calculation LVars are unavailable.
        if(voltMode===0) selVolts=getAVar('ELECTRICAL MAIN BUS VOLTAGE:@LEFT_BUS, volts');
        else if(voltMode===1) selVolts=getAVar('ELECTRICAL MAIN BUS VOLTAGE:@CENTER_BUS, volts');
        else if(voltMode===2) selVolts=getAVar('ELECTRICAL MAIN BUS VOLTAGE:@RIGHT_BUS, volts');
        else if(voltMode===3) selVolts=getAVar('ELECTRICAL MAIN BUS VOLTAGE:@TRIPLE_FED_BUS, volts');
        else if(voltMode===4) selVolts=(getLVar('bksq_ExternalPowerAvailable','Bool')==1 && getLVar('bksq_ExternalPowerOn','Bool')==1) ? 28.1 : 0;
        else selVolts=getAVar('ELECTRICAL MAIN BUS VOLTAGE:@BATTERY_BUS, volts');
      }
      setValDisplay('gVoltsDC', fmtNum(selVolts,1));

      /* Electrical switches */
      setToggleVisual('battBtn','battInd', getLVar('VAR_BATTERYTIE','Number')==1);

      var genLOn=getAVar('GENERAL ENG MASTER ALTERNATOR:1, Bool')==1;
      var genLRst=getLVar('VAR_GENERATORRESET_L','Bool')==1;
      if(!genLOn) _genLPhase=0;
      setLamps(['genLRstLamp','genLOnLamp','genLOffLamp'], genLRst?0:(genLOn?1:2));

      var genROn=getAVar('GENERAL ENG MASTER ALTERNATOR:2, Bool')==1;
      var genRRst=getLVar('VAR_GENERATORRESET_R','Bool')==1;
      if(!genROn) _genRPhase=0;
      setLamps(['genRRstLamp','genROnLamp','genROffLamp'], genRRst?0:(genROn?1:2));
      setToggleVisual('gpuBtn','gpuInd', getLVar('BKSQ_EXTERNALPOWERON','Bool')==1);
      setToggleVisual('extPwrBtn','extPwrInd', getLVar('var_ExternalPowerSwitch','Bool')==1);
      setToggleVisual('battAmpsBtn','battAmpsInd', getLVar('var_BatteryAmpsMode','Bool')==1);
      var btO=getLVar('var_busTieManOpen','Bool'), btC=getLVar('var_busTieManClose','Bool');
      setLamps(['btCloseLamp','btNormLamp','btOpenLamp'], btC==1?0:btO==1?2:1);

      var stbyOn=getLVar('var_StandbyInstrumentsSwitch','Bool')==1;
      setLamps(['stbyOnLamp','stbyOffLamp'], stbyOn?0:1);
      setToggleVisual('stbyPwrBtn','stbyPwrInd', getLVar('var_StandbyBatteryPushTest','Bool')==1);
      setToggleVisual('avBlowBtn','avBlowInd', getLVar('var_AvionicsAlternateBlowerSwitch','Bool')==1);
      setToggleVisual('gndCommBtn','gndCommInd', getLVar('var_GroundComOn','Bool')==1);

      /* Engine */
      setLamps(['ignLArmLamp','ignLOffLamp'], getLVar('var_AutoIgnitionSwitch_L','Bool')==1 ? 0 : 1);
      setLamps(['ignRArmLamp','ignROffLamp'], getLVar('var_AutoIgnitionSwitch_R','Bool')==1 ? 0 : 1);
      var af=getLVar('var_AutoFeatherSwitch','Number');
      setLamps(['afTestLamp','afArmLamp','afOffLamp'], af==0?0:af==2?2:1);
      setToggleVisual('propSyncBtn','propSyncInd', getAVar('PROP SYNC ACTIVE, bool')==1);
      var gov=getLVar('var_PropGovTestSwitch_Override','Number');
      setLamps(['govGovLamp','govNormLamp','govLowLamp'], gov==0?0:gov==2?2:1);
      var stL=getLVar('var_StarterSwitch_L','Number');
      setLamps(['stLOnLamp','stLOffLamp','stLSOLamp'], stL==0?0:stL==2?2:1);
      var stR=getLVar('var_StarterSwitch_R','Number');
      setLamps(['stROnLamp','stROffLamp','stRSOLamp'], stR==0?0:stR==2?2:1);

      /* Fuel gauges */
      var fuelConv = getLVar('AAOFuelConv','Number');
      var isKg = (fuelConv==1);
      var unitLabel = isKg ? 'KG' : 'LBS';
      var galToLbs=6.7;
      var totalLGal=getAVar('FUEL LEFT QUANTITY, gallons');
      var totalRGal=getAVar('FUEL RIGHT QUANTITY, gallons');
      var auxLGal=getAVar('FUEL TANK LEFT AUX QUANTITY, gallons');
      var auxRGal=getAVar('FUEL TANK RIGHT AUX QUANTITY, gallons');
      var aftL = getLVar('var_AftTankQuantityButton_L','Bool')==1 || getLVar('VAR_AFTTANKQUANTITYBUTTON_L','Bool')==1;
      var aftR = getLVar('var_AftTankQuantityButton_R','Bool')==1 || getLVar('VAR_AFTTANKQUANTITYBUTTON_R','Bool')==1;
      var fuelLGal = aftL ? auxLGal : totalLGal;
      var fuelRGal = aftR ? auxRGal : totalRGal;
      var fuelL = (fuelLGal!==undefined&&fuelLGal!==null) ? Number(fuelLGal)*galToLbs : getLVar('AAOFuelL','Number');
      var fuelR = (fuelRGal!==undefined&&fuelRGal!==null) ? Number(fuelRGal)*galToLbs : getLVar('AAOFuelR','Number');
      if(isKg){
        if(fuelL!==undefined&&fuelL!==null) fuelL = Number(fuelL)*0.45359237;
        if(fuelR!==undefined&&fuelR!==null) fuelR = Number(fuelR)*0.45359237;
      }
      setValDisplay('gFuelL', fmtNum(fuelL,0));
      setValDisplay('gFuelR', fmtNum(fuelR,0));
      var uL=document.getElementById('gFuelLUnit');
      var uR=document.getElementById('gFuelRUnit');
      if(uL) uL.textContent=unitLabel;
      if(uR) uR.textContent=unitLabel;

      var fTemp = getLVar('var_FuelTemperature','Number');
      if(fTemp!==undefined&&fTemp!==null) fTemp = Number(fTemp) - 273.15;
      if(fTemp===undefined||fTemp===null) fTemp=getAVar('ENG OIL TEMPERATURE:1, celsius');
      if(fTemp===undefined||fTemp===null) fTemp=getAVar('AMBIENT TEMPERATURE, celsius');
      setValDisplay('gFuelTemp', fmtNum(fTemp,0));

      /* Fuel switches */
      setToggleVisual('fuelPumpLBtn','fuelPumpLInd', getLVar('var_StandbyFuelPump_L','Number')==1);
      setToggleVisual('fuelPumpRBtn','fuelPumpRInd', getLVar('var_StandbyFuelPump_R','Number')==1);
      setToggleVisual('aftTankLBtn','aftTankLInd', aftL);
      setToggleVisual('aftTankRBtn','aftTankRInd', aftR);
      var xf=getLVar('var_FuelTransferKnob','Number');
      setLamps(['xferRtoLLamp','xferOffLamp','xferLtoRLamp'], xf==0?0:xf==2?2:1);

      /* Lower pedestal — trim + brake */
      var pt=getLVar('var_PitchTrimModeSwitch','Number');
      setLamps(['ptNormLamp','ptOffLamp','ptStbyLamp'], pt==0?0:pt==2?2:1);
      setToggleVisual('rtmBtn','rtmInd', getLVar('var_RollTrimModeSwitch','Bool')==1);
      setToggleVisual('rudTmBtn','rudTmInd', getLVar('var_RudderTrimModeSwitch','Bool')==1);
      setToggleVisual('prkBrkBtn','prkBrkInd', getAVar('BRAKE PARKING POSITION, bool')==1);
} catch(e){} }

/* AVNCS transponder lamps + ident */

function getXpdrState(){ try { return webApi.GetSimVar('(A:TRANSPONDER STATE:1, Enum)'); } catch(e){ return 0; } }
function getXpdrIdent(){ try { return webApi.GetSimVar('(A:TRANSPONDER IDENT:1, Bool)'); } catch(e){ return 0; } }
function setXpdrModeVisual(st){
  var altL=document.getElementById('xpdrAltLamp');
  var stbyL=document.getElementById('xpdrStbyLamp');
  if(!altL||!stbyL) return;
  altL.classList.toggle('on', st===4);
  stbyL.classList.toggle('on', st===1);
}
var _xpdrIdentVal = 0, _xpdrLastPoll = 0;
function updateXpdrVisuals(){
  var st = getXpdrState();
  var on = (st !== 0);
  setToggleVisual('xpdrPwrToggle','xpdrPwrInd', on);
  setXpdrModeVisual(st);
  var now = Date.now();
  if (now - _xpdrLastPoll > 300) { _xpdrIdentVal = getXpdrIdent(); _xpdrLastPoll = now; }
  setToggleVisual('xpdrIdentBtn','xpdrIdentInd', _xpdrIdentVal==1);
}
function toggleXpdrPwr(){ try { sendP('SSP_AVNCS_XPDR_PWR_TOGGLE'); setTimeout(updateXpdrVisuals, 120); } catch(e){} }
function toggleXpdrMode(){ try { sendP('SSP_AVNCS_XPDR_MODE_TOGGLE'); setTimeout(updateXpdrVisuals, 120); } catch(e){} }
function xpdrIdent(){ try { sendP('SSP_AVNCS_XPDR_IDENT_PRESS'); setTimeout(function(){ _xpdrLastPoll=0; updateXpdrVisuals(); }, 120); } catch(e){} }

function pollAvncsXpdr(){ try { updateXpdrVisuals(); } catch(e){} }

window.SSP_PANEL_OVERRIDES = window.SSP_PANEL_OVERRIDES || {};
window.SSP_PANEL_OVERRIDES.onPoll = function(panelId, ctx){
  if (panelId === 'ecs') pollEcs();
  else if (panelId === 'pedestal') pollPedestal();
  else if (panelId === 'autopilot') pollAvncsXpdr();
};
window.SSP_PANEL_OVERRIDES.polls = window.SSP_PANEL_OVERRIDES.polls || {};
/* COM spacing: interior uses (A:COM SPACING MODE:n, enum) 0 != for non-default; lamp = both radios in 8.33 / non-zero spacing */
window.SSP_PANEL_OVERRIDES.polls.rtu833Both = function () {
  try {
    var m1 = Number(getAVar('COM SPACING MODE:1, Enum'));
    var m2 = Number(getAVar('COM SPACING MODE:2, Enum'));
    if (!isFinite(m1) || !isFinite(m2)) return;
    var on = m1 !== 0 && m2 !== 0;
    setToggleVisual('rtu833Btn', 'rtu833Ind', on);
  } catch (e) {}
};
